const MOBILITY_LABELS = ["non-mobilizable", "mobilizable", "conjugative"];
const MOBILITY_SHORT = ["non-mob", "mobilizable", "conjugative"];

/* ── API detection and inference ────────────────────────────────────── */

let _apiOnline = false;

async function checkAPI() {
  try {
    const res = await fetch("/health", { signal: AbortSignal.timeout(2000) });
    if (res.ok) {
      const data = await res.json();
      _apiOnline = data.status === "ok";
    }
  } catch { _apiOnline = false; }
}

async function apiPredict(seq) {
  const res = await fetch("/predict", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ sequence_id: "web_query", dna: seq }),
    signal: AbortSignal.timeout(60000),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || `API error ${res.status}`);
  }
  return res.json();
}

/* ── Utilities ─────────────────────────────────────────────────────── */

function confidenceLabel(prob) {
  if (prob >= 0.80) return "HIGH";
  if (prob >= 0.60) return "MEDIUM";
  return "LOW";
}

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }

function revcomp(dna) {
  const map = { A: "T", C: "G", G: "C", T: "A", N: "N" };
  return dna.replace(/[ACGTN]/g, c => map[c]).split("").reverse().join("");
}

function validateDNA(text) {
  const cleaned = text.replace(/[\s\r\n>-]/g, "").replace(/[a-z]/g, c => c.toUpperCase()).trim();
  if (!cleaned) return { valid: false, error: "Empty sequence after cleaning." };
  if (cleaned.length > 300000) return { valid: false, error: `Sequence too long: ${cleaned.length.toLocaleString()} > 300,000 bp.` };
  const nonACGT = cleaned.replace(/[ACGT]/g, "").length;
  if (nonACGT > 0) {
    return { valid: true, cleaned, nonACGT, warning: `${nonACGT.toLocaleString()} non-ACGT characters will be ignored.` };
  }
  return { valid: true, cleaned, nonACGT: 0 };
}

function parseFASTA(text) {
  const records = [];
  let id = null, seq = [];
  for (const line of text.split(/\r?\n/)) {
    const t = line.trim();
    if (t.startsWith(">")) {
      if (id !== null) records.push({ id, seq: seq.join("") });
      id = t.slice(1).split(/\s/)[0] || `seq${records.length + 1}`;
      seq = [];
    } else if (t) seq.push(t.replace(/\s+/g, "").toUpperCase());
  }
  if (id !== null) records.push({ id, seq: seq.join("") });
  return records;
}

function seqStats(seq) {
  const s = (seq || "").replace(/[^ACGT]/g, "").toUpperCase();
  const len = s.length;
  if (!len) return { length: 0, gc: 0, a: 0, c: 0, g: 0, t: 0 };
  const counts = { A: 0, C: 0, G: 0, T: 0 };
  for (let i = 0; i < len; i++) counts[s[i]]++;
  return {
    length: len,
    gc: (counts.G + counts.C) / len,
    a: counts.A, c: counts.C, g: counts.G, t: counts.T,
  };
}

function fmtPct(x, digits) {
  if (digits === undefined) digits = 1;
  return (x * 100).toFixed(digits) + "%";
}
function fmtInt(x) { return x.toLocaleString("en-US"); }

/* ── Offline inference fallback: k-mer + motif heuristic ───────────── */

const AMR_MOTIFS = [
  "GGATCC", "GAATTC", "AAGCTT", "CTGCAG", "CCCGGG",
  "TCCCTG", "CATGAG", "GGTCTC", "CACACT", "AGATCT",
];
const MOB_MOTIFS = [
  "CGATCG", "CGCATG", "GATATC", "GCTCGG", "CCGCGG",
  "GCATGC", "CGTCTC",
];

function scoreMotifHits(count, randomFloor, fullScale) {
  return clamp((count - randomFloor) / Math.max(1, fullScale), 0, 1);
}
const AMR_RANDOM_FLOOR = 17;
const AMR_FULL_SCALE = 30;
const MOB_RANDOM_FLOOR = 10;
const MOB_FULL_SCALE = 20;

function countMotifs(seq, motifs) {
  let total = 0;
  for (const m of motifs) {
    let pos = 0;
    while ((pos = seq.indexOf(m, pos)) !== -1) { total++; pos += 1; }
  }
  return total;
}

function findMotifHotspots(seq, motifs, topK) {
  if (topK === undefined) topK = 3;
  const windowSize = 500;
  const stride = 250;
  if (seq.length < windowSize) return [];
  const hits = [];
  for (let start = 0; start + windowSize <= seq.length; start += stride) {
    const slice = seq.slice(start, start + windowSize);
    let n = 0;
    for (const m of motifs) {
      let pos = 0;
      while ((pos = slice.indexOf(m, pos)) !== -1) { n++; pos += 1; }
    }
    hits.push({ start, end: start + windowSize, hits: n });
  }
  hits.sort((a, b) => b.hits - a.hits);
  return hits.slice(0, topK);
}

function offlineInference(seq) {
  const clean = seq.replace(/[^ACGT]/g, "").toUpperCase();
  const len = clean.length;
  if (len < 100) return null;

  const stats = seqStats(clean);

  const kmers = new Map();
  for (let k = 4; k <= 6; k++) {
    for (let i = 0; i <= len - k; i++) {
      const mer = clean.substring(i, i + k);
      kmers.set(mer, (kmers.get(mer) || 0) + 1);
    }
  }

  const amrCount = countMotifs(clean, AMR_MOTIFS);
  const mobCount = countMotifs(clean, MOB_MOTIFS);

  const amrRaw = scoreMotifHits(amrCount, AMR_RANDOM_FLOOR, AMR_FULL_SCALE);
  const mobRaw = scoreMotifHits(mobCount, MOB_RANDOM_FLOOR, MOB_FULL_SCALE);

  const rc = revcomp(clean);
  const amrRCCount = countMotifs(rc, AMR_MOTIFS);
  const mobRCCount = countMotifs(rc, MOB_MOTIFS);
  const amrRC = scoreMotifHits(amrRCCount, AMR_RANDOM_FLOOR, AMR_FULL_SCALE);
  const mobRC = scoreMotifHits(mobRCCount, MOB_RANDOM_FLOOR, MOB_FULL_SCALE);
  const amrConsensus = (amrRaw + amrRC) / 2;
  const mobConsensus = (mobRaw + mobRC) / 2;

  const expScore = clamp(amrConsensus * 0.55 + mobConsensus * 0.35 + stats.gc * 0.10, 0, 1);

  let mobProbs;
  if (mobConsensus > 0.30) {
    mobProbs = [0.12, 0.30, 0.58];
  } else if (mobConsensus > 0.15) {
    mobProbs = [0.22, 0.52, 0.26];
  } else {
    mobProbs = [0.72, 0.18, 0.10];
  }
  mobProbs[0] += (stats.gc - 0.5) * 0.05;
  mobProbs[2] += (0.5 - stats.gc) * 0.04;
  const mSum = mobProbs.reduce((a, b) => a + b, 0);
  mobProbs = mobProbs.map(p => Math.max(0.02, p / mSum));
  const mSum2 = mobProbs.reduce((a, b) => a + b, 0);
  mobProbs = mobProbs.map(p => p / mSum2);

  const amrHotspots = findMotifHotspots(clean, AMR_MOTIFS, 2);
  const mobHotspots = findMotifHotspots(clean, MOB_MOTIFS, 2);
  const evidence = [];
  let idx = 0;
  for (const h of mobHotspots) {
    if (h.hits === 0) continue;
    evidence.push({
      window: idx++,
      weight: clamp(h.hits / 5, 0.1, 0.95),
      region: "Conjugation module",
      signal: `${h.hits} mob motif hits @ ${h.start.toLocaleString()}-${h.end.toLocaleString()} bp`,
    });
  }
  for (const h of amrHotspots) {
    if (h.hits === 0) continue;
    evidence.push({
      window: idx++,
      weight: clamp(h.hits / 5, 0.1, 0.95),
      region: "AMR motif cluster",
      signal: `${h.hits} restriction-site hits @ ${h.start.toLocaleString()}-${h.end.toLocaleString()} bp`,
    });
  }
  const evidenceRnd = lcg(((len * 1103515245) ^ 0x5DEECE66D) >>> 0);
  const generalSignals = [
    { region: "GC-rich region",        signal: `GC content ${fmtPct(stats.gc)}` },
    { region: "Low-complexity region", signal: "few 6-mer repeats" },
    { region: "Replication origin",    signal: "AT-rich track" },
  ];
  for (const g of generalSignals) {
    if (evidence.length >= 5) break;
    evidence.push({
      window: idx++,
      weight: clamp(0.3 + evidenceRnd() * 0.3, 0.1, 0.95),
      region: g.region,
      signal: g.signal,
    });
  }
  evidence.sort((a, b) => b.weight - a.weight);
  evidence.forEach((e, i) => { e.window = i; });

  return {
    mobility_probs: mobProbs,
    amr_probability: amrConsensus,
    expansion_probability: expScore,
    mobility_label: MOBILITY_LABELS[mobProbs.indexOf(Math.max(...mobProbs))],
    gc_content: stats.gc,
    length: stats.length,
    evidence,
  };
}

function interpretPrediction(pred) {
  const mobConf = confidenceLabel(Math.max(...pred.mobility_probs));
  const amrConf = confidenceLabel(pred.amr_probability);
  const expConf = confidenceLabel(pred.expansion_probability);
  const mobIdx = pred.mobility_probs.indexOf(Math.max(...pred.mobility_probs));

  const mobDesc = {
    0: "Plasmid does not carry identifiable conjugation or mobilization machinery. Horizontal transfer is unlikely without helper plasmids.",
    1: "Plasmid carries mobilization (MOB) genes but lacks a full conjugation system. Transfer requires a co-resident conjugative helper plasmid.",
    2: "Plasmid carries a complete conjugation system (MPF/T4SS). Self-transmissible; autonomous horizontal transfer is possible.",
  };

  const amrNote = amrConf === "HIGH"
    ? "AMR-associated k-mer signatures detected. Possible resistance gene families include beta-lactamase, tetracycline resistance, or aminoglycoside resistance clusters."
    : amrConf === "MEDIUM"
    ? "Weak AMR signal — no confident gene family assignment. Confirm with ResFinder / AMRFinder before downstream use."
    : "AMR signal below detection threshold. ResFinder/AMRFinder negative result is consistent.";

  const expReasoning = [];
  if (mobIdx > 0 && amrConf === "HIGH") {
    expReasoning.push("Co-occurrence of mobility machinery and AMR cargo increases spread risk.");
  }
  if (mobIdx === 2) expReasoning.push("Self-transmissible plasmid — autonomous spread possible.");
  else if (mobIdx === 1) expReasoning.push("Mobilizable plasmid — spread depends on helper plasmid.");
  else expReasoning.push("Non-mobilizable plasmid — spread requires natural transformation.");

  const riskWeight = [0.4, 0.3, 0.3];
  const mobileProb = 1 - pred.mobility_probs[0];
  const riskScore = clamp(
    riskWeight[0] * mobileProb +
    riskWeight[1] * pred.amr_probability +
    riskWeight[2] * pred.expansion_probability,
    0, 1
  );

  return {
    mobility: {
      label: MOBILITY_LABELS[mobIdx],
      description: mobDesc[mobIdx],
      confidence: mobConf,
      class_probs: {
        "non-mobilizable": pred.mobility_probs[0],
        "mobilizable": pred.mobility_probs[1],
        "conjugative": pred.mobility_probs[2],
      },
    },
    amr: {
      probability: pred.amr_probability,
      confidence: amrConf,
      note: amrNote,
    },
    expansion: {
      probability: pred.expansion_probability,
      confidence: expConf,
      reasoning: expReasoning.join(" "),
    },
    overall_risk_score: riskScore,
    disclaimer: "Tarama sinyalidir; klinik, çevresel veya biyogüvenlik kararlarında tek başına kullanılamaz.",
  };
}

/* ── LCG for evidence generation ──────────────────────────────────── */

function lcg(seed) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0x100000000;
  };
}

