/* ── UI: prediction page ───────────────────────────────────────────── */

function updateModeIndicator(live) {
  const el = document.getElementById("mode-indicator");
  if (!el) return;
  if (live) {
    el.innerHTML = '<span class="live-dot"></span> Live model <span class="mode-detail">(ensemble, v14+v15)</span>';
    el.className = "mode-indicator live";
  } else {
    el.innerHTML = '<span class="offline-dot"></span> Offline heuristic';
    el.className = "mode-indicator offline";
  }
}

function setupPredictionPage() {
  const textInput = document.getElementById("sequence-input");
  const fileInput = document.getElementById("file-input");
  const predictBtn = document.getElementById("predict-btn");
  const sampleBtn = document.getElementById("sample-btn");
  const sampleAmrBtn = document.getElementById("sample-amr-btn");
  const sampleQuietBtn = document.getElementById("sample-quiet-btn");

  const clearBtn = document.getElementById("clear-btn");
  const progressBar = document.getElementById("progress-bar");
  const progressFill = document.getElementById("progress-fill");
  const errorBanner = document.getElementById("error-banner");
  const resultsDiv = document.getElementById("results");
  const validationMsg = document.getElementById("validation-msg");
  const statLength = document.getElementById("stat-length");
  const statGc = document.getElementById("stat-gc");
  const statRecords = document.getElementById("stat-records");
  const copyBtn = document.getElementById("copy-cmd-btn");
  const copyFeedback = document.getElementById("copy-feedback");

  // Detect API mode on load
  checkAPI().then(() => updateModeIndicator(_apiOnline));

  function showError(msg) {
    errorBanner.textContent = msg;
    errorBanner.style.display = "block";
  }
  function clearError() { errorBanner.style.display = "none"; }

  function setProgress(pct, error) {
    progressBar.classList.add("active");
    progressFill.style.width = pct + "%";
    progressFill.className = "fill" + (error ? " error" : "");
    progressBar.setAttribute("aria-valuenow", String(Math.round(pct)));
    if (pct >= 100) setTimeout(() => progressBar.classList.remove("active"), 600);
  }

  function updateStats() {
    const raw = textInput.value;
    if (!raw.trim()) {
      statLength.textContent = "0";
      statGc.textContent = "\u2014";
      statRecords.textContent = "0";
      return;
    }
    const records = parseFASTA(raw);
    statRecords.textContent = String(records.length);
    if (records.length > 0) {
      const stats = seqStats(records[0].seq);
      statLength.textContent = fmtInt(stats.length);
      statGc.textContent = stats.length > 0 ? fmtPct(stats.gc, 1) : "\u2014";
    } else {
      const stats = seqStats(raw);
      statLength.textContent = fmtInt(stats.length);
      statGc.textContent = stats.length > 0 ? fmtPct(stats.gc, 1) : "\u2014";
    }
  }

  function getSequence() {
    const raw = textInput.value;
    const records = parseFASTA(raw);
    let cleaned;
    let warnings = [];
    if (records.length > 0) {
      if (records.length > 1) {
        warnings.push(`Multiple FASTA records detected (${records.length}); using the first.`);
      }
      const v = validateDNA(records[0].seq);
      if (!v.valid) { showValidation(v.error); return null; }
      cleaned = v.cleaned;
      if (v.warning) warnings.push(v.warning);
    } else {
      const v = validateDNA(raw);
      if (!v.valid) { showValidation(v.error); return null; }
      cleaned = v.cleaned;
      if (v.warning) warnings.push(v.warning);
    }
    if (warnings.length) {
      validationMsg.textContent = warnings.join(" ");
      validationMsg.className = "validation-error show warning";
    } else {
      clearValidation();
    }
    return cleaned;
  }

  function showValidation(msg) {
    validationMsg.textContent = msg;
    validationMsg.className = "validation-error show";
  }
  function clearValidation() {
    validationMsg.className = "validation-error";
  }

  function renderResults(pred, interp) {
    document.getElementById("mob-value").textContent = interp.mobility.label;
    const mobConf = document.getElementById("mob-confidence");
    mobConf.textContent = `confidence: ${interp.mobility.confidence}`;
    mobConf.className = `confidence ${interp.mobility.confidence}`;

    document.getElementById("amr-value").textContent = fmtPct(pred.amr_probability, 1);
    const amrConf = document.getElementById("amr-confidence");
    amrConf.textContent = `confidence: ${interp.amr.confidence}`;
    amrConf.className = `confidence ${interp.amr.confidence}`;

    document.getElementById("exp-value").textContent = fmtPct(pred.expansion_probability, 1);
    const expConf = document.getElementById("exp-confidence");
    expConf.textContent = `confidence: ${interp.expansion.confidence}`;
    expConf.className = `confidence ${interp.expansion.confidence}`;

    document.getElementById("risk-value").textContent = fmtPct(interp.overall_risk_score, 1);

    const probBars = document.getElementById("prob-bars");
    const entries = Object.entries(interp.mobility.class_probs);
    const maxP = Math.max(...entries.map(([, v]) => v));
    probBars.innerHTML = entries.map(([label, p], i) => {
      const isMax = p === maxP;
      const pct = (p * 100).toFixed(1);
      return `
        <div class="prob-row ${isMax ? "max" : ""}">
          <div class="prob-label">${MOBILITY_SHORT[i]}</div>
          <div class="prob-bar"><div class="prob-fill" style="width:${pct}%"></div></div>
          <div class="prob-value">${pct}%</div>
        </div>`;
    }).join("");

    const interpEl = document.getElementById("interpretation");
    interpEl.innerHTML = `
      <div class="task-section">
        <h4>Mobility &mdash; <span class="${interp.mobility.confidence}">${interp.mobility.label} (${interp.mobility.confidence})</span></h4>
        <p>${interp.mobility.description}</p>
      </div>
      <div class="task-section">
        <h4>Antimicrobial Resistance &mdash; <span class="${interp.amr.confidence}">${interp.amr.confidence}</span></h4>
        <p>${interp.amr.note}</p>
      </div>
      <div class="task-section">
        <h4>Geographic Expansion &mdash; <span class="${interp.expansion.confidence}">${interp.expansion.confidence}</span></h4>
        <p>${interp.expansion.reasoning}</p>
      </div>
      <div class="disclaimer">${interp.disclaimer}</div>
    `;

    const evBody = document.getElementById("evidence-body");
    evBody.innerHTML = pred.evidence && pred.evidence.length ? pred.evidence.map((e, idx) => `
      <tr class="ev-row" data-idx="${idx}" style="cursor:pointer">
        <td><span class="ev-toggle">▶</span> #${e.window}</td>
        <td><div class="weight-bar"><div class="weight-fill" style="width:${(e.weight * 100).toFixed(0)}%"></div></div><span class="weight-num">${(e.weight * 100).toFixed(0)}%</span></td>
        <td>${e.region}</td>
        <td>—</td>
      </tr>
      <tr class="ev-dna" data-idx="${idx}" style="display:none">
        <td colspan="4"><code class="ev-seq">${e.signal || ''}</code></td>
      </tr>
    `).join("") : "<tr><td colspan='4'>No real evidence windows from API (model attention scores not exposed via /predict). Run <code>dna interpret</code> locally for full evidence analysis.</td></tr>";
    if (!evBody.dataset.listener) {
      evBody.addEventListener("click", (evt) => {
        const row = evt.target.closest(".ev-row");
        if (!row) return;
        const idx = row.dataset.idx;
        const dnaRow = evBody.querySelector(`.ev-dna[data-idx="${idx}"]`);
        if (!dnaRow) return;
        const toggle = row.querySelector(".ev-toggle");
        const shown = dnaRow.style.display !== "none";
        dnaRow.style.display = shown ? "none" : "table-row";
        toggle.textContent = shown ? "▶" : "▼";
      });
      evBody.dataset.listener = "1";
    }

    resultsDiv.style.display = "block";
    resultsDiv.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  async function runPrediction() {
    clearError();
    const seq = getSequence();
    if (!seq) return;
    if (seq.length < 100) {
      showError(`Sequence too short for prediction: ${seq.length} bp (need \u2265 100).`);
      return;
    }

    predictBtn.disabled = true;
    const originalBtn = predictBtn.innerHTML;
    predictBtn.innerHTML = '<span class="spinner" aria-hidden="true"></span>Running...';

    try {
      setProgress(15);
      await new Promise(r => setTimeout(r, 30));

      let pred, interp;

      if (_apiOnline) {
        setProgress(40);
        const apiResult = await apiPredict(seq);
        setProgress(70);
        // Map API result to our format
        const windowLevels = [
          { offset: 0, count: 16, stride: 256, size: 512 },
          { offset: 16, count: 8, stride: 1024, size: 2048 },
          { offset: 24, count: 4, stride: 4096, size: 8192 },
        ];
        function windowPos(flatIdx) {
          for (const l of windowLevels) {
            if (flatIdx < l.offset + l.count) return (flatIdx - l.offset) * l.stride;
          }
          return 0;
        }
        function dnaSnippet(pos, len) {
          const s = pos - Math.floor(len / 2);
          const e = s + len;
          const clipped = seq.slice(Math.max(0, s), Math.min(seq.length, e));
          if (s < 0) return '...' + clipped.slice(-len);
          if (e > seq.length) return clipped.slice(0, len) + '...';
          return clipped;
        }
        pred = {
          mobility_probs: apiResult.mobility_probs,
          amr_probability: apiResult.amr_probability,
          expansion_probability: apiResult.expansion_probability,
          gc_content: null,
          length: seq.length,
          evidence: (() => {
            function inList(idx, list) { return list && list.some(w => w.window === idx); }
            return (apiResult.top_windows || []).map((w) => {
              const kind = [];
              if (inList(w.window, apiResult.top_mobility_windows)) kind.push("Mobility");
              if (inList(w.window, apiResult.top_amr_windows)) kind.push("AMR");
              if (inList(w.window, apiResult.top_expansion_windows)) kind.push("Expansion");
              if (!kind.length) kind.push("Combined");
              const pos = windowPos(w.window);
              return {
                window: w.window,
                weight: w.weight,
                region: kind.join(" + "),
                signal: dnaSnippet(pos, 60),
              };
            });
          })(),
        };
        interp = interpretPrediction(pred);
        // Add API note
        interp.api_note = "Prediction from the Cassiopeia Prime ensemble model (v14+v15).";
      } else {
        setProgress(45);
        await new Promise(r => setTimeout(r, 30));
        const offline = offlineInference(seq);
        if (!offline) {
          showError("Inference failed: sequence too short or invalid.");
          setProgress(100, true);
          return;
        }
        setProgress(80);
        await new Promise(r => setTimeout(r, 30));
        pred = offline;
        interp = interpretPrediction(pred);
      }

      setProgress(100);
      renderResults(pred, interp);
    } catch (err) {
      showError("Prediction failed: " + (err.message || err));
      setProgress(100, true);
    } finally {
      predictBtn.disabled = false;
      predictBtn.innerHTML = originalBtn;
    }
  }

  predictBtn.addEventListener("click", runPrediction);

  fileInput.addEventListener("change", (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      showError("File too large (>5 MB). Use a smaller FASTA.");
      fileInput.value = "";
      return;
    }
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const records = parseFASTA(ev.target.result);
        if (records.length === 0) {
          const cleaned = (ev.target.result || "").replace(/[^ACGT\s]/gi, "");
          if (cleaned) {
            textInput.value = cleaned;
          } else {
            showError("No valid FASTA records found in file.");
            return;
          }
        } else {
          textInput.value = records.map(r => `>${r.id}\n${chunk(r.seq, 80)}`).join("\n");
        }
        clearError();
        clearValidation();
        updateStats();
      } catch (err) {
        showError("Failed to read file: " + err.message);
      }
    };
    reader.onerror = () => showError("File read error.");
    reader.readAsText(file);
  });

  function loadSample(builder) {
    const { id, seq } = builder();
    textInput.value = `>${id}\n${chunk(seq, 80)}`;
    clearError();
    clearValidation();
    resultsDiv.style.display = "none";
    updateStats();
  }
  sampleBtn.addEventListener("click", () => loadSample(SAMPLES.conj));
  sampleAmrBtn.addEventListener("click", () => loadSample(SAMPLES.amr));
  sampleQuietBtn.addEventListener("click", () => loadSample(SAMPLES.quiet));
  document.getElementById("sample-oxa48-btn").addEventListener("click", () => loadSample(SAMPLES.oxa48));
  document.getElementById("sample-ndm1-btn").addEventListener("click", () => loadSample(SAMPLES.ndm1));



  clearBtn.addEventListener("click", () => {
    textInput.value = "";
    fileInput.value = "";
    resultsDiv.style.display = "none";
    clearError();
    clearValidation();
    updateStats();
    textInput.focus();
  });

  textInput.addEventListener("input", updateStats);
  textInput.addEventListener("keydown", (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {
      e.preventDefault();
      runPrediction();
    }
  });

  if (copyBtn) {
    copyBtn.addEventListener("click", async () => {
      const text = document.getElementById("repro-cmd").textContent;
      try {
        await navigator.clipboard.writeText(text);
        copyFeedback.textContent = "Copied!";
      } catch {
        const ta = document.createElement("textarea");
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        try { document.execCommand("copy"); copyFeedback.textContent = "Copied!"; }
        catch { copyFeedback.textContent = "Copy failed \u2014 select manually."; }
        document.body.removeChild(ta);
      }
      setTimeout(() => { copyFeedback.textContent = ""; }, 2000);
    });
  }

  updateStats();
}

function chunk(s, n) {
  const out = [];
  for (let i = 0; i < s.length; i += n) out.push(s.slice(i, i + n));
  return out.join("\n");
}

/* ── UI: benchmark page ────────────────────────────────────────────── */

function setupBenchmarkPage() {
  const own = BENCHMARK_DATA.splits;
  const splitLabels = { validation: "Validation", test: "Test", heldout: "Held-out" };

  const accBody = document.getElementById("accuracy-body");
  const ownRow = own.heldout;
  const accRows = [
    {
      name: "Cassiopeia Prime",
      ba: ownRow.mobility_balanced_accuracy,
      amr: ownRow.amr_auroc,
      exp: ownRow.expansion_auroc,
      ts: ownRow.task_score,
      params: BENCHMARK_DATA.parameters,
      lat: BENCHMARK_DATA.fasta_latency_ms_6kb,
      own: true,
    },
  ];
  for (const [name, data] of Object.entries(BENCHMARK_DATA.baselines)) {
    accRows.push({
      name,
      ba: data.mobility_ba,
      amr: data.amr_auroc,
      exp: data.expansion_auroc,
      ts: (data.mobility_ba + data.amr_auroc + data.expansion_auroc) / 3,
      params: data.params_m * 1e6,
      lat: data.latency_ms,
      own: false,
    });
  }
  accBody.innerHTML = accRows.map(r => `
    <tr class="${r.own ? "own" : ""}">
      <td>${r.name}</td>
      <td class="${r.own ? "best" : ""}">${r.ba.toFixed(2)}%</td>
      <td class="${r.own ? "best" : ""}">${r.amr.toFixed(2)}%</td>
      <td class="${r.own ? "best" : ""}">${r.exp.toFixed(2)}%</td>
      <td class="${r.own ? "best" : ""}">${r.ts.toFixed(2)}%</td>
      <td>${r.params >= 1e6 ? (r.params / 1e6).toFixed(2) + "M" : (r.params / 1e3).toFixed(1) + "K"}</td>
      <td>${r.lat.toFixed(1)}</td>
    </tr>
  `).join("");

  const splitBody = document.getElementById("split-body");
  splitBody.innerHTML = Object.entries(own).map(([key, data]) => `
    <tr>
      <td>${splitLabels[key] || key}</td>
      <td>n=${fmtInt(data.size)}</td>
      <td>${data.mobility_balanced_accuracy.toFixed(2)}%</td>
      <td>${data.amr_auroc.toFixed(2)}%</td>
      <td>${data.expansion_auroc.toFixed(2)}%</td>
      <td><strong>${data.task_score.toFixed(2)}%</strong></td>
    </tr>
  `).join("");

  const keyMetrics = [
    ["Model version", `v${BENCHMARK_DATA.model_version} (champion: ${BENCHMARK_DATA.champion})`],
    ["Trainable parameters", fmtInt(BENCHMARK_DATA.parameters)],
    ["Checkpoint size", `${BENCHMARK_DATA.checkpoint_mb.toFixed(2)} MB (\u00d72 for ensemble)`],
    ["FASTA latency (6 kb)", `${BENCHMARK_DATA.fasta_latency_ms_6kb.toFixed(1)} ms`],
    ["Cached latency", `${BENCHMARK_DATA.cached_latency_ms.toFixed(2)} ms/seq`],
    ["Train split size", "1,466 plasmids"],
    ["Validation / Test / Held-out", "286 / 296 / 1,200"],
    ["Training budget", "2,048 plasmids max"],
    ["Calibration", "L-BFGS temperature + bias scaling"],
    ["Inference", "Reverse-complement averaged"],
    ["Ensemble", "v14 (weight 0.47) + v15 (weight 0.53)"],
    ["Held-out task score", `<strong>${ownRow.task_score.toFixed(2)}%</strong>`],
  ];
  document.getElementById("key-metrics-body").innerHTML = keyMetrics.map(([k, v]) =>
    `<tr><td>${k}</td><td>${v}</td></tr>`
  ).join("");

  const meta = document.getElementById("bench-meta");
  meta.textContent = `Benchmark date: ${BENCHMARK_DATA.snapshot_date} \u00B7 Device: ${BENCHMARK_DATA.device} \u00B7 Test set: held-out (n=${fmtInt(ownRow.size)}) \u00B7 Cassiopeia v${BENCHMARK_DATA.model_version}`;

  document.querySelectorAll(".copy-btn[data-copy]").forEach(btn => {
    btn.addEventListener("click", async () => {
      const pre = btn.previousElementSibling;
      if (!pre) return;
      const text = pre.textContent;
      const fb = btn.nextElementSibling;
      try {
        await navigator.clipboard.writeText(text);
        if (fb) fb.textContent = "Copied!";
      } catch {
        if (fb) fb.textContent = "Copy failed";
      }
      setTimeout(() => { if (fb) fb.textContent = ""; }, 2000);
    });
  });
}

/* ── Tabs ──────────────────────────────────────────────────────────── */

function setupTabs() {
  const tabs = document.querySelectorAll(".tab");
  if (!tabs.length) return;
  tabs.forEach(tab => {
    tab.addEventListener("click", () => activateTab(tab));
    tab.addEventListener("keydown", (e) => {
      if (e.key === "ArrowRight" || e.key === "ArrowLeft") {
        e.preventDefault();
        const order = Array.from(tabs);
        const idx = order.indexOf(tab);
        const next = order[(idx + (e.key === "ArrowRight" ? 1 : -1) + order.length) % order.length];
        next.focus();
        activateTab(next);
      }
    });
  });
  function activateTab(tab) {
    tabs.forEach(t => {
      t.classList.toggle("active", t === tab);
      t.setAttribute("aria-selected", t === tab ? "true" : "false");
      t.tabIndex = t === tab ? 0 : -1;
    });
    document.querySelectorAll(".tab-content").forEach(panel => {
      panel.classList.toggle("active", panel.id === tab.dataset.tab);
    });
  }
}

/* ── Init ──────────────────────────────────────────────────────────── */

document.addEventListener("DOMContentLoaded", () => {
  if (document.getElementById("predict-btn")) setupPredictionPage();
  if (document.getElementById("accuracy-body")) setupBenchmarkPage();
  setupTabs();
});
